import java.util.ArrayList;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) {
        Library lib = new Library();
        lib.addBook("Matilda", "Roald Dahl");
        lib.addBook("Holes", "Louis Sachar");
        lib.addBook("Wonder", "R.J. Palacio");

        lib.borrow("Matilda", "Sam");
        lib.borrow("Holes", "Ava");
        lib.borrow("Matilda", "Leo");

        lib.giveBack("Holes");
        lib.report();
    }
}

class Book {
    String title;
    String author;
    boolean isOut;

    Book(String title, String author) {
        this.title = title;
        this.author = author;
        this.isOut = false;
    }
}

class Library {
    ArrayList<Book> books = new ArrayList<>();
    HashMap<String, String> borrowedBy = new HashMap<>();

    void addBook(String title, String author) {
        books.add(new Book(title, author));
    }

    Book find(String title) {
        for (Book b : books) {
            if (b.title.equals(title)) {
                return b;
            }
        }
        return null;
    }

    void borrow(String title, String person) {
        Book b = find(title);
        if (b == null) {
            System.out.println("No book called " + title);
        } else if (b.isOut) {
            System.out.println(title + " is already borrowed by " + borrowedBy.get(title));
        } else {
            b.isOut = true;
            borrowedBy.put(title, person);
            System.out.println(person + " borrowed " + title);
        }
    }

    void giveBack(String title) {
        Book b = find(title);
        if (b != null && b.isOut) {
            b.isOut = false;
            borrowedBy.remove(title);
            System.out.println(title + " was returned");
        }
    }

    void report() {
        int out = 0;
        for (Book b : books) {
            if (b.isOut) {
                out++;
            }
        }
        System.out.println("Books out: " + out + " of " + books.size());
    }
}

