import java.util.ArrayList;
import java.util.HashMap;

public class Main {
    public static void main(String[] args) {
        ArrayList<HashMap<String, String>> tasks = new ArrayList<>();

        addTask(tasks, "Design database", "HIGH");
        addTask(tasks, "Write API endpoints", "HIGH");
        addTask(tasks, "Add unit tests", "MEDIUM");
        addTask(tasks, "Write README", "LOW");

        markDone(tasks, "Design database");
        markDone(tasks, "Write API endpoints");

        report(tasks);
    }

    static void addTask(ArrayList<HashMap<String, String>> tasks, String title, String priority) {
        HashMap<String, String> t = new HashMap<>();
        t.put("title", title);
        t.put("status", "TODO");
        t.put("priority", priority);
        tasks.add(t);
    }

    static void markDone(ArrayList<HashMap<String, String>> tasks, String title) {
        for (HashMap<String, String> t : tasks) {
            if (t.get("title").equals(title)) {
                t.put("status", "DONE");
                return;
            }
        }
    }

    static void report(ArrayList<HashMap<String, String>> tasks) {
        int done = 0;
        for (HashMap<String, String> t : tasks) {
            String mark = t.get("status").equals("DONE") ? "✓" : "○";
            System.out.println(mark + " [" + t.get("priority") + "] " + t.get("title"));
            if (t.get("status").equals("DONE")) done++;
        }
        System.out.println("Progress: " + done + "/" + tasks.size() + " done");
    }
}

