import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        Quiz quiz = new Quiz();
        quiz.addQuestion("Capital of Japan?", "Tokyo");
        quiz.addQuestion("2 + 2 equals?", "4");
        quiz.addQuestion("Color of the sky?", "Blue");

        quiz.answer("Capital of Japan?", "Tokyo");
        quiz.answer("2 + 2 equals?", "5");
        quiz.answer("Color of the sky?", "Blue");

        quiz.report();
    }
}

class Question {
    String prompt;
    String correct;

    Question(String prompt, String correct) {
        this.prompt = prompt;
        this.correct = correct;
    }
}

class Quiz {
    ArrayList<Question> questions = new ArrayList<>();
    int score = 0;

    void addQuestion(String prompt, String correct) {
        questions.add(new Question(prompt, correct));
    }

    Question find(String prompt) {
        for (Question q : questions) {
            if (q.prompt.equals(prompt)) {
                return q;
            }
        }
        return null;
    }

    void answer(String prompt, String given) {
        Question q = find(prompt);
        if (q == null) {
            System.out.println("No such question");
        } else if (q.correct.equals(given)) {
            this.score = this.score + 1;
            System.out.println("Correct: " + prompt);
        } else {
            System.out.println("Wrong: " + prompt);
        }
    }

    void report() {
        System.out.println("Score: " + score + " of " + questions.size());
    }
}
